import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as i,b as r}from"./app-291b7530.js";const t="/assets/MQ发送消息流程-271ebc17.png",c={},o=r('<h2 id="_3种发送方式" tabindex="-1"><a class="header-anchor" href="#_3种发送方式" aria-hidden="true">#</a> 3种发送方式</h2><p>RocketMQ支持3种消息发送方式：同步，异步，单向</p><ul><li>同步：生产者发送消息后，同步等待，直到返回结果</li><li>异步：生产者发送消息时，指定回调函数，发送消息后，立即返回，程序继续向下执行；消息发送成功或失败的回调函数在一个新线程中执行</li><li>单向：生产者发送消息后直接返回，不等待结果，也不指定回调函数，也就是只管发送</li></ul><p>这里只通过同步消息的发送来深入了解MQ的消息发送</p><h2 id="高可用设计" tabindex="-1"><a class="header-anchor" href="#高可用设计" aria-hidden="true">#</a> 高可用设计</h2><p>RokcetMQ为了实现消息发送的高可用，有两个非常重要的机制：</p><ul><li>重试机制：对于同步消息，发送失败后，默认会再重试两次</li><li>故障规避机制：当消息第一次发送失败后，下一次重试发送消息的时候会尽量避免刚刚失败的broker，而是选择其他broker，提高消息发送的成功率</li></ul><h2 id="发送流程" tabindex="-1"><a class="header-anchor" href="#发送流程" aria-hidden="true">#</a> 发送流程</h2><figure><img src="'+t+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure>',9),l=[o];function n(s,d){return a(),i("div",null,l)}const f=e(c,[["render",n],["__file","消息发送.html.vue"]]);export{f as default};
